// src/client.ts
import { ProviderBase, diffNodes } from "@slop-ai/core";

class SlopClientImpl extends ProviderBase {
  registrations = new Map;
  transports;
  subscriptions = new Map;
  rebuildQueued = false;
  constructor(options, transport) {
    super(options);
    this.transports = Array.isArray(transport) ? transport : [transport];
  }
  register(path, descriptor) {
    this.registrations.set(path, descriptor);
    this.scheduleRebuild();
  }
  unregister(path, opts) {
    if (opts?.recursive) {
      const prefix = path + "/";
      for (const key of [...this.registrations.keys()]) {
        if (key === path || key.startsWith(prefix)) {
          this.registrations.delete(key);
        }
      }
    } else {
      this.registrations.delete(path);
    }
    this.scheduleRebuild();
  }
  scope(path, descriptor) {
    if (descriptor) {
      this.register(path, descriptor);
    }
    return createScopedClient(this, path);
  }
  flush() {
    if (this.rebuildQueued) {
      this.rebuildQueued = false;
      this.rebuild();
    }
  }
  asyncAction(params, fn, options) {
    return {
      estimate: "async",
      params,
      label: options?.label,
      description: options?.description,
      handler: (rawParams) => {
        const taskId = `task-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`;
        const abortController = new AbortController;
        const task = {
          id: taskId,
          signal: abortController.signal,
          update: (progress, message) => {
            this.register(`tasks/${taskId}`, {
              type: "status",
              props: { progress, message, status: "running", action: options?.label ?? "task" },
              meta: { salience: 0.8 },
              ...options?.cancelable && {
                actions: {
                  cancel: {
                    dangerous: true,
                    handler: () => {
                      abortController.abort();
                      this.register(`tasks/${taskId}`, {
                        type: "status",
                        props: { status: "cancelled", message: "Cancelled" },
                        meta: { salience: 0.3 }
                      });
                      setTimeout(() => this.unregister(`tasks/${taskId}`), 1e4);
                    }
                  }
                }
              }
            });
          }
        };
        task.update(0, options?.label ? `${options.label}...` : "Starting...");
        fn(rawParams, task).then((result) => {
          this.register(`tasks/${taskId}`, {
            type: "status",
            props: { progress: 1, message: "Complete", status: "done", result },
            meta: { salience: 0.5 }
          });
          setTimeout(() => this.unregister(`tasks/${taskId}`), 30000);
        }).catch((err) => {
          this.register(`tasks/${taskId}`, {
            type: "status",
            props: { progress: 0, message: err.message ?? String(err), status: "failed" },
            meta: { salience: 1, urgency: "high" }
          });
        });
        return { __async: true, taskId };
      }
    };
  }
  start() {
    for (const t of this.transports) {
      t.start();
      t.onMessage((msg) => this.handleMessage(msg, t));
    }
  }
  stop() {
    for (const t of this.transports)
      t.stop();
  }
  getRegistrations() {
    return this.registrations;
  }
  broadcast(_globalOps) {
    const version = this.getVersion();
    for (const [, sub] of this.subscriptions) {
      const newTree = this.getOutputTree({
        path: sub.path,
        depth: sub.depth,
        filter: sub.filter
      });
      if (!sub.lastTree) {
        sub.lastTree = JSON.parse(JSON.stringify(newTree));
        sub.transport.send({
          type: "snapshot",
          id: sub.id,
          version,
          tree: newTree
        });
        continue;
      }
      const ops = diffNodes(sub.lastTree, newTree);
      sub.lastTree = JSON.parse(JSON.stringify(newTree));
      if (ops.length > 0) {
        sub.transport.send({
          type: "patch",
          subscription: sub.id,
          version,
          ops
        });
      }
    }
  }
  scheduleRebuild() {
    if (this.rebuildQueued)
      return;
    this.rebuildQueued = true;
    queueMicrotask(() => {
      if (!this.rebuildQueued)
        return;
      this.rebuildQueued = false;
      this.rebuild();
    });
  }
  handleMessage(msg, transport) {
    switch (msg.type) {
      case "connect":
        transport.send(this.helloMessage());
        break;
      case "subscribe": {
        const outputTree = this.getOutputTree({
          path: msg.path ?? "/",
          depth: msg.depth ?? -1,
          filter: msg.filter
        });
        this.subscriptions.set(msg.id, {
          id: msg.id,
          path: msg.path ?? "/",
          depth: msg.depth ?? -1,
          filter: msg.filter,
          lastTree: JSON.parse(JSON.stringify(outputTree)),
          transport
        });
        transport.send({
          type: "snapshot",
          id: msg.id,
          version: this.getVersion(),
          tree: outputTree
        });
        break;
      }
      case "unsubscribe":
        this.subscriptions.delete(msg.id);
        break;
      case "query":
        transport.send(this.snapshotMessage(msg.id, { path: msg.path, depth: msg.depth, filter: msg.filter }));
        break;
      case "invoke":
        this.handleInvoke(msg, transport);
        break;
    }
  }
  async handleInvoke(msg, transport) {
    const result = await this.executeInvoke(msg);
    transport.send(result);
  }
}
function createScopedClient(parent, prefix) {
  return {
    register(path, descriptor) {
      parent.register(`${prefix}/${path}`, descriptor);
    },
    unregister(path, opts) {
      parent.unregister(`${prefix}/${path}`, opts);
    },
    scope(path, descriptor) {
      return parent.scope(`${prefix}/${path}`, descriptor);
    },
    flush() {
      parent.flush();
    },
    asyncAction: parent.asyncAction.bind(parent),
    stop() {}
  };
}

// src/postmessage-transport.ts
function createPostMessageTransport(options = {}) {
  const messageHandlers = [];
  let listener = null;
  let metaTag = null;
  return {
    send(message) {
      window.postMessage(JSON.parse(JSON.stringify({ slop: true, message })), "*");
    },
    onMessage(handler) {
      messageHandlers.push(handler);
    },
    start() {
      listener = (event) => {
        if (event.source !== window)
          return;
        if (event.data?.slop !== true)
          return;
        const msg = event.data.message;
        if (!msg?.type)
          return;
        for (const h of messageHandlers)
          h(msg);
      };
      window.addEventListener("message", listener);
      if (options.discover !== false && typeof document !== "undefined" && !document.querySelector('meta[name="slop"][content="postmessage"]')) {
        metaTag = document.createElement("meta");
        metaTag.name = "slop";
        metaTag.content = "postmessage";
        document.head.appendChild(metaTag);
      }
    },
    stop() {
      if (listener) {
        window.removeEventListener("message", listener);
        listener = null;
      }
      if (metaTag) {
        metaTag.remove();
        metaTag = null;
      }
    }
  };
}

// src/websocket-transport.ts
var DEFAULT_DESKTOP_URL = "ws://localhost:9339/slop";
function createWebSocketTransport(url = DEFAULT_DESKTOP_URL, options = {}) {
  const messageHandlers = [];
  let ws = null;
  let stopped = false;
  let reconnectDelay = 1000;
  let reconnectTimer = null;
  let metaTag = null;
  function connect() {
    if (stopped)
      return;
    try {
      ws = new WebSocket(url);
    } catch {
      scheduleReconnect();
      return;
    }
    ws.onopen = () => {
      reconnectDelay = 1000;
    };
    ws.onmessage = (event) => {
      try {
        const msg = JSON.parse(event.data);
        if (msg?.type) {
          for (const h of messageHandlers)
            h(msg);
        }
      } catch {}
    };
    ws.onclose = () => {
      ws = null;
      scheduleReconnect();
    };
    ws.onerror = () => {};
  }
  function scheduleReconnect() {
    if (stopped || reconnectTimer)
      return;
    reconnectTimer = setTimeout(() => {
      reconnectTimer = null;
      connect();
    }, reconnectDelay);
    reconnectDelay = Math.min(reconnectDelay * 2, 30000);
  }
  return {
    send(message) {
      if (ws?.readyState === WebSocket.OPEN) {
        ws.send(JSON.stringify(message));
      }
    },
    onMessage(handler) {
      messageHandlers.push(handler);
    },
    start() {
      stopped = false;
      connect();
      if (options.discover !== false && typeof document !== "undefined") {
        const selector = `meta[name="slop"][content="${url}"]`;
        if (!document.querySelector(selector)) {
          metaTag = document.createElement("meta");
          metaTag.name = "slop";
          metaTag.content = url;
          document.head.appendChild(metaTag);
        }
      }
    },
    stop() {
      stopped = true;
      if (reconnectTimer) {
        clearTimeout(reconnectTimer);
        reconnectTimer = null;
      }
      if (ws) {
        ws.onclose = null;
        ws.close();
        ws = null;
      }
      if (metaTag) {
        metaTag.remove();
        metaTag = null;
      }
    }
  };
}

// src/index.ts
import {
  ProviderBase as ProviderBase2,
  pick,
  omit,
  action,
  assembleTree,
  diffNodes as diffNodes2,
  prepareTree,
  getSubtree,
  truncateTree,
  autoCompact,
  filterTree,
  countNodes
} from "@slop-ai/core";
function createSlop(options) {
  const transports = [];
  const enabledTransports = options.transports ?? [
    "postmessage",
    ...options.websocketUrl ?? options.desktopUrl ? ["websocket"] : []
  ];
  const websocketUrl = options.websocketUrl ?? options.desktopUrl;
  if (enabledTransports.includes("postmessage")) {
    transports.push(createPostMessageTransport({ discover: options.postmessageDiscover }));
  }
  if (enabledTransports.includes("websocket")) {
    const url = typeof websocketUrl === "string" ? websocketUrl : undefined;
    transports.push(createWebSocketTransport(url, { discover: options.websocketDiscover }));
  }
  const client = new SlopClientImpl(options, transports);
  client.start();
  return client;
}
export {
  truncateTree,
  prepareTree,
  pick,
  omit,
  getSubtree,
  filterTree,
  diffNodes2 as diffNodes,
  createWebSocketTransport,
  createSlop,
  createPostMessageTransport,
  countNodes,
  autoCompact,
  assembleTree,
  action,
  SlopClientImpl,
  ProviderBase2 as ProviderBase
};
